// 종목별로 group → 4개 지표 계산
const byT = {};
for (const it of items) {
  const t = it.json.ticker;
  (byT[t] ||= []).push(it.json);
}

const ema = (arr, n) => {
  const k = 2 / (n + 1);
  const out = []; let prev = arr[0] ?? 0;
  arr.forEach((v, i) => { prev = i === 0 ? v : v * k + prev * (1 - k); out.push(prev); });
  return out;
};

const result = [];
for (const t of Object.keys(byT)) {
  const rows = byT[t].sort((a,b) => String(a.date).localeCompare(String(b.date)));
  const closes = rows.map(r => parseFloat(r.close)).filter(v => !isNaN(v));
  if (closes.length < 26) continue;

  // RSI 14
  const rsi = []; let avgG = 0, avgL = 0;
  for (let i = 1; i < closes.length; i++) {
    const d = closes[i] - closes[i-1];
    const g = Math.max(d, 0), l = Math.max(-d, 0);
    if (i <= 14) { avgG += g/14; avgL += l/14; }
    else { avgG = (avgG*13 + g)/14; avgL = (avgL*13 + l)/14; }
    if (i >= 14) {
      const rs = avgL === 0 ? 100 : avgG/avgL;
      rsi[i] = 100 - 100/(1+rs);
    }
  }

  const ema12 = ema(closes, 12);
  const ema26 = ema(closes, 26);
  const macd = closes.map((_, i) => ema12[i] - ema26[i]);
  const sig = ema(macd, 9);

  for (let i = 0; i < rows.length; i++) {
    const win = closes.slice(Math.max(0, i-19), i+1);
    const m20 = i < 19 ? null : win.reduce((a,b)=>a+b, 0)/20;
    const std = m20 ? Math.sqrt(win.reduce((s,v)=>s+(v-m20)**2, 0)/win.length) : null;
    result.push({json: {
      date: rows[i].date,
      ticker: rows[i].ticker,
      close: closes[i],
      MA20: m20,
      RSI14: rsi[i] ?? null,
      BB_upper: m20 ? m20 + 2*std : null,
      BB_lower: m20 ? m20 - 2*std : null,
      MACD: macd[i],
      Signal: sig[i],
      Hist: macd[i] - sig[i],
    }});
  }
}
return result;
